impl Ord for State {
    fn cmp(&self, other: &Self) -> Ordering {
        // Notice the order is reversed to make it a min-heap
        other.cost.cmp(&self.cost)
    }
}

impl PartialOrd for State {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        Some(self.cmp(other))
    }
}

// Dijkstra's algorithm implementation
// Calculates shortest paths from a source node to all other nodes.
// If 'is_carrying' is true, it uses the tax-modified edge weights.
fn dijkstra(n: usize, adj: &Vec<Vec<(usize, i64)>>, start_node: usize, is_carrying: bool) -> Vec<i64> {
    let mut dist: Vec<i64> = vec![i64::MAX; n];
    let mut heap = BinaryHeap::new();

    dist[start_node] = 0;
    heap.push(State { cost: 0, node: start_node });

    while let Some(State { cost, node }) = heap.pop() {
        if cost > dist[node] {
            continue;
