        for &(neighbor, weight) in &adj[node] {
            let new_cost = cost + weight;
            if new_cost < dist[neighbor] {
                dist[neighbor] = new_cost;
                heap.push(State { cost: new_cost, node: neighbor });
            }
        }
    }
    dist
