fn solve(n: i64, prices: Vec<i64>, roads: Vec<Vec<i64>>) -> Vec<i64> {
    let n_usize = n as usize;

    // Adjacency lists for two scenarios:
    // 1. Traveling without apples (cost = cost_i)
    // 2. Traveling with apples (cost = cost_i * tax_i)
    let mut adj_no_apple: Vec<Vec<(usize, i64)>> = vec![vec![]; n_usize];
    let mut adj_with_apple: Vec<Vec<(usize, i64)>> = vec![vec![]; n_usize];

    for road in roads {
        let u = road[0] as usize;
        let v = road[1] as usize;
        let cost = road[2];
        let tax = road[3];

        // Edge weights for no apple
        let weight_no_apple = cost;
        adj_no_apple[u].push((v, weight_no_apple));
        adj_no_apple[v].push((u, weight_no_apple));

        // Edge weights for carrying apple (cost * tax)
        // Since cost and tax are up to 10^9 and 100, their product fits in i64.
        let weight_with_apple = cost * tax;
        adj_with_apple[u].push((v, weight_with_apple));
        adj_with_apple[v].push((u, weight_with_apple));
    }

    // Calculate shortest paths for all possible scenarios:
    // 1. Distances from any node j to any node i while carrying no apples (to reach j)
    //    This is equivalent to running Dijkstra from j using adj_no_apple.
    //    We need Shortest Path FROM j TO i (unweighted/no apple cost).
    //    Since roads are bidirectional, shortest path j->i is the same as i->j.
    //    Let D_out[j][i] be the shortest path cost from j to i without apples.
    // 2. Distances from any node j to any node i while carrying apples (to return from j)
    //    Let D_in[j][i] be the shortest path cost from j to i with apples.
    //    Since roads are bidirectional, shortest path j->i is the same as i->j.
    //    So, D_out[j][i] and D_in[j][i] are symmetric.

    // Pre-calculate all-pairs shortest paths (APSP) for both modes.
    // Since N is small (<= 1000) and we need APSP, running N Dijkstra's is O(N * (E+NlogN)).
    // Given E is small (<= 2000), N*E is manageable.

    // D_no_apple[j][i]: shortest path cost from j to i (no apple)
    let mut d_no_apple = vec![vec![i64::MAX; n_usize]; n_usize];
    // D_with_apple[j][i]: shortest path cost from j to i (with apple)
    let mut d_with_apple = vec![vec![i64::MAX; n_usize]; n_usize];

    for j in 0..n_usize {
        // Dijkstra to find shortest paths starting from j
        let dists_no = dijkstra(n_usize, &adj_no_apple, j, false);
        let dists_with = dijkstra(n_usize, &adj_with_apple, j, true);

        // Store results in symmetric matrices for easy lookup (i.e., d[i][j] = dist from j to i)
        // Since Dijkstra gives dist from j to i, we store it at d[i][j] if we want to read it as i->j.
        // However, it's simpler to store it as d[j][i] = shortest path cost from j to i.
        for i in 0..n_usize {
            d_no_apple[j][i] = dists_no[i];
            d_with_apple[j][i] = dists_with[i];
        }
    }

    let mut ans: Vec<i64> = vec![0; n_usize];

    // Calculate ans[i] for each starting shop i
    for i in 0..n_usize {
        // Option 1: Buy at shop i directly
        let min_cost_i = prices[i];

        // Option 2: Go to shop j, buy, return to i
        // Total Cost = (Path i -> j, no apple) + prices[j] + (Path j -> i, with apple)

        let mut min_cost_indirect = i64::MAX;

        for j in 0..n_usize {
            if i == j {
                continue;
            }

            // Path i -> j (no apple)
            let path_i_to_j = d_no_apple[i][j];

            // Path j -> i (with apple)
            let path_j_to_i = d_with_apple[j][i];

