    let n_usize = n as usize;

    // Adjacency list for the graph
    // adj[u] stores tuples: (v, cost_no_apple, tax_multiplier)
    let mut adj: Vec<Vec<(usize, i64, i64)>> = vec![vec![]; n_usize];
    for road in roads {
        let u = road[0] as usize;
        let v = road[1] as usize;
        let cost = road[2];
        let tax = road[3];

        // Roads are bidirectional
        adj[u].push((v, cost, tax));
        adj[v].push((u, cost, tax));
    }

    // --- Step 1: Calculate minimum cost to travel between any two shops (Air travel) ---
    // We need two shortest path calculations:
    // 1. Cost to go from any shop 'j' to any shop 'i' *without* apples (cost_no_apple)
    // 2. Cost to go from any shop 'j' to any shop 'i' *with* apples (cost_with_apple)

