    let mut dist_empty = vec![vec![i64::MAX; n_usize]; n_usize];
    // dist_full[i][j]: Min cost to travel from i to j with apples (taxed costs).
    let mut dist_full = vec![vec![i64::MAX; n_usize]; n_usize];

