        let mut heap_full = BinaryHeap::new();
        dist_full[start_node][start_node] = 0;
        heap_full.push(State { cost: 0, node: start_node });

        while let Some(State { cost, node }) = heap_full.pop() {
            if cost > dist_full[start_node][node] {
                continue;
            }

            for &(neighbor, cost_no_apple, tax_multiplier) in &adj[node] {
                // Cost when carrying apples = original cost * tax_multiplier
                let cost_with_apple = cost_no_apple * tax_multiplier;
                let new_cost = cost + cost_with_apple;

                if new_cost < dist_full[start_node][neighbor] {
                    dist_full[start_node][neighbor] = new_cost;
                    heap_full.push(State { cost: new_cost, node: neighbor });
                }
            }
        }
