use std::collections::{BinaryHeap, HashMap};
use std::cmp::Ordering;

// Define a state for Dijkstra's algorithm: (cost, node)
// We use a tuple for the priority queue, and implement comparison manually 
// or use a wrapper struct to make it a min-heap.
#[derive(Copy, Clone, Eq, PartialEq)]
struct State {
    cost: i64,
    position: usize,
}

// The priority queue in Rust's BinaryHeap is a max-heap, so we invert the comparison for cost
impl Ord for State {
    fn cmp(&self, other: &Self) -> Ordering {
        other.cost.cmp(&self.cost) // Reversed order for min-heap behavior
    }
}

impl PartialOrd for State {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        Some(self.cmp(other))
    }
}

fn dijkstra(n: usize, adj: &Vec<Vec<Vec<(usize, i64, i64)>>>, start_node: usize, target_node: usize, is_carrying: bool) -> i64 {
    let mut dist: Vec<i64> = vec![i64::MAX; n];
    let mut heap = BinaryHeap::new();

    dist[start_node] = 0;
    heap.push(State { cost: 0, position: start_node });

    while let Some(State { cost, position }) = heap.pop() {
        if cost > dist[position] {
            continue;
        }

        if position == target_node {
            return cost;
        }

        // Iterate over neighbors
        for &(neighbor, edge_cost, edge_tax) in &adj[position] {
            let travel_cost = if is_carrying {
                // Carrying apples: cost * tax
                edge_cost * edge_tax
            } else {
                // Empty hands: cost
                edge_cost
            };

            let next_cost = cost + travel_cost;

            if next_cost < dist[neighbor] {
                dist[neighbor] = next_cost;
                heap.push(State { cost: next_cost, position: neighbor });
            }
        }
    }
    i64::MAX // Should not happen if the graph is connected enough
}


